create table accounting_accounts (active bit not null, system_account bit, admin_user_id bigint, created_at datetime(6), id bigint not null auto_increment, shop_id bigint, code varchar(255) not null, created_by varchar(255), name varchar(255) not null, type enum ('ASSET','EQUITY','EXPENSE','LIABILITY','REVENUE') not null, primary key (id)) engine=InnoDB;
create table app_notifications (read_flag bit, created_at datetime(6), id bigint not null auto_increment, recipient_user_id bigint, shop_id bigint, message varchar(1000), target_tab varchar(255), title varchar(255), type varchar(255), recipient_role enum ('ADMIN','CUSTOMER','EMPLOYEE','OWNER','SUPER_ADMIN'), primary key (id)) engine=InnoDB;
create table appointments (front_quantity integer, rear_quantity integer, appointment_date datetime(6) not null, created_at datetime(6), customer_id bigint, front_tire_id bigint, id bigint not null auto_increment, location_id bigint, rear_tire_id bigint, reminder_at datetime(6), shop_id bigint, cancel_reason varchar(255), confirmation_status varchar(255), customer_name varchar(255) not null, email varchar(255), notes varchar(255), phone varchar(255) not null, reminder_status varchar(255), tire_size varchar(255), vehicle varchar(255), service_type enum ('BALANCING','INSTALLATION','REPAIR','ROTATION') not null, status enum ('BOOKED','CANCELLED','COMPLETED'), primary key (id)) engine=InnoDB;
create table audit_logs (created_at datetime(6), entity_id bigint, id bigint not null auto_increment, shop_id bigint, action varchar(255), entity_type varchar(255), message varchar(255), performed_by varchar(255), primary key (id)) engine=InnoDB;
create table company_settings (tax_rate decimal(38,2), id bigint not null auto_increment, shop_id bigint, invoice_terms varchar(1000), address varchar(255), logo_url varchar(255), phone varchar(255), shop_name varchar(255) not null, primary key (id)) engine=InnoDB;
create table customer_notifications (read_flag bit, created_at datetime(6), customer_id bigint not null, id bigint not null auto_increment, message varchar(1000), title varchar(255), type varchar(255), primary key (id)) engine=InnoDB;
create table customer_vehicles (created_at datetime(6), customer_id bigint not null, id bigint not null auto_increment, location_id bigint, shop_id bigint, front_tire_size varchar(255), make varchar(255), model varchar(255), nickname varchar(255), plate_number varchar(255), rear_tire_size varchar(255), tire_setup varchar(255), tire_size varchar(255), vehicle_year varchar(255), primary key (id)) engine=InnoDB;
create table employee_attendance (work_date date not null, worked_hours decimal(6,2), clock_in datetime(6), clock_out datetime(6), created_at datetime(6), employee_id bigint not null, id bigint not null auto_increment, location_id bigint, shop_id bigint, updated_at datetime(6), notes TEXT, absence_decision enum ('EXCUSED','PAID_ABSENCE','SICK_DAY','UNPAID_ABSENCE','UNRESOLVED','VACATION') not null, status enum ('ABSENT','LATE','MANUAL_ADJUSTED','PARTIAL','PRESENT') not null, primary key (id)) engine=InnoDB;
create table employee_loans (installment_amount decimal(12,2), original_amount decimal(12,2) not null, remaining_balance decimal(12,2) not null, created_at datetime(6), employee_id bigint not null, id bigint not null auto_increment, shop_id bigint, updated_at datetime(6), notes TEXT, status enum ('ACTIVE','CANCELLED','PAID_OFF') not null, primary key (id)) engine=InnoDB;
create table estimate_items (line_total decimal(38,2), quantity integer not null, unit_price decimal(38,2), estimate_id bigint, id bigint not null auto_increment, tire_id bigint, item_name varchar(255), item_type enum ('SERVICE','TIRE') not null, primary key (id)) engine=InnoDB;
create table estimates (subtotal decimal(38,2), tax_amount decimal(38,2), tax_rate decimal(38,2), total decimal(38,2), valid_until date, appointment_id bigint, converted_invoice_id bigint, created_at datetime(6), customer_id bigint, id bigint not null auto_increment, location_id bigint, shop_id bigint, updated_at datetime(6), customer_name varchar(255) not null, email varchar(255), estimate_number varchar(255), notes TEXT, phone varchar(255), vehicle varchar(255), status enum ('APPROVED','CANCELLED','CONVERTED','DECLINED','DRAFT','EXPIRED','REJECTED','SENT','VIEWED') not null, primary key (id)) engine=InnoDB;
create table expenses (due_date date, expense_date date, subtotal decimal(38,2), tax_amount decimal(38,2), total decimal(38,2), admin_user_id bigint, created_at datetime(6), expense_account_id bigint, id bigint not null auto_increment, location_id bigint, paid_at datetime(6), shop_id bigint, vendor_id bigint, category varchar(255), created_by varchar(255), custom_category varchar(255), custom_payment_method varchar(255), notes varchar(255), payment_method varchar(255), status varchar(255), vendor varchar(255) not null, category_key enum ('BANK_FEES','EQUIPMENT','INSURANCE','INVENTORY','MARKETING','OTHER','PAYROLL','PROFESSIONAL_SERVICES','RENT','REPAIRS_MAINTENANCE','SUPPLIES','UTILITIES'), payment_method_key enum ('BANK_TRANSFER','CASH','CHEQUE','CREDIT_CARD','DEBIT','OTHER'), primary key (id)) engine=InnoDB;
create table invoice_items (quantity integer not null, total_price decimal(38,2) not null, unit_price decimal(38,2), id bigint not null auto_increment, invoice_id bigint, tire_id bigint, item_name varchar(255), item_type enum ('SERVICE','TIRE') not null, primary key (id)) engine=InnoDB;
create table invoices (amount_paid decimal(38,2), balance_due decimal(38,2), due_date date, subtotal decimal(38,2), tax_amount decimal(38,2), tax_rate decimal(38,2), total decimal(38,2), appointment_id bigint, created_at datetime(6), customer_id bigint, id bigint not null auto_increment, location_id bigint, paid_at datetime(6), shop_id bigint, customer_name varchar(255) not null, payment_method varchar(255), phone varchar(255) not null, status varchar(255), vehicle varchar(255), primary key (id)) engine=InnoDB;
create table journal_entries (entry_date date not null, admin_user_id bigint, created_at datetime(6), id bigint not null auto_increment, location_id bigint, reference_id bigint, shop_id bigint, description varchar(255) not null, posted_by varchar(255), reference_type varchar(255), source varchar(255), primary key (id)) engine=InnoDB;
create table journal_entry_lines (credit decimal(38,2) not null, debit decimal(38,2) not null, account_id bigint not null, id bigint not null auto_increment, journal_entry_id bigint not null, memo varchar(255), primary key (id)) engine=InnoDB;
create table payroll_adjustments (amount decimal(12,2) not null, created_at datetime(6), employee_loan_id bigint, id bigint not null auto_increment, payroll_record_id bigint not null, notes TEXT, type enum ('BONUS','DEDUCTION','LOAN_DEDUCTION','OTHER','PENALTY','REIMBURSEMENT','TAX_DEDUCTION') not null, primary key (id)) engine=InnoDB;
create table payroll_periods (end_date date not null, start_date date not null, created_at datetime(6), id bigint not null auto_increment, location_id bigint, paid_at datetime(6), shop_id bigint, updated_at datetime(6), notes TEXT, status enum ('APPROVED','CANCELLED','PAID','PENDING') not null, primary key (id)) engine=InnoDB;
create table payroll_records (accounting_synced boolean default false not null, bonus_amount decimal(12,2), deduction_amount decimal(12,2), gross_pay decimal(12,2), hourly_rate decimal(10,2), loan_deduction_amount decimal(12,2), net_pay decimal(12,2), other_deduction_amount decimal(12,2), overtime_hours decimal(6,2), penalty_amount decimal(12,2), regular_hours decimal(6,2), reimbursement_amount decimal(12,2), tax_deduction_amount decimal(12,2), total_deductions decimal(12,2), accounting_entry_id bigint, created_at datetime(6), employee_id bigint not null, id bigint not null auto_increment, paid_at datetime(6), payroll_period_id bigint not null, updated_at datetime(6), notes TEXT, status enum ('APPROVED','CANCELLED','PAID','PENDING') not null, primary key (id)) engine=InnoDB;
create table payroll_shift_signups (created_at datetime(6), employee_id bigint not null, id bigint not null auto_increment, slot_id bigint not null, primary key (id)) engine=InnoDB;
create table payroll_shift_slots (end_time time(6) not null, required_employees integer not null, shift_date date not null, start_time time(6) not null, created_at datetime(6), id bigint not null auto_increment, payroll_period_id bigint not null, notes TEXT, primary key (id)) engine=InnoDB;
create table refresh_tokens (created_at datetime(6), expires_at datetime(6) not null, id bigint not null auto_increment, user_id bigint not null, token varchar(255) not null, primary key (id)) engine=InnoDB;
create table shop_locations (active bit not null, customer_facing bit not null, created_at datetime(6), id bigint not null auto_increment, shop_id bigint not null, updated_at datetime(6), address varchar(255), city varchar(255), email varchar(255), name varchar(255) not null, phone varchar(255), postal_code varchar(255), province varchar(255), type enum ('MOBILE','MOBILE_SERVICE','OTHER','STORAGE','STORE','WAREHOUSE') not null, primary key (id)) engine=InnoDB;
create table shops (active bit not null, created_at datetime(6), id bigint not null auto_increment, owner_admin_id bigint, updated_at datetime(6), address varchar(255), email varchar(255), legal_name varchar(255), name varchar(255) not null, phone varchar(255), subscription_plan enum ('BASIC','ENTERPRISE','PREMIUM') not null, primary key (id)) engine=InnoDB;
create table tires (aspect_ratio integer, price decimal(38,2) not null, quantity integer not null, reserved_quantity integer, rim_size integer, width integer not null, created_at datetime(6), id bigint not null auto_increment, location_id bigint, shop_id bigint, updated_at datetime(6), brand varchar(255) not null, location varchar(255), model varchar(255), season varchar(255), condition_type enum ('NEW','USED'), primary key (id)) engine=InnoDB;
create table users (hourly_rate decimal(38,2), is_active bit, payroll_enabled bit, created_at datetime(6), id bigint not null auto_increment, location_id bigint, shop_id bigint, email varchar(255) not null, employment_type varchar(255), full_name varchar(255) not null, password_hash varchar(255) not null, phone varchar(255) not null, role varchar(255) not null, primary key (id)) engine=InnoDB;
create table vendors (admin_user_id bigint, created_at datetime(6), id bigint not null auto_increment, shop_id bigint, category varchar(255), created_by varchar(255), custom_category varchar(255), email varchar(255), name varchar(255) not null, notes varchar(255), phone varchar(255), category_key enum ('EQUIPMENT','GENERAL','INSURANCE','MARKETING','OTHER','PARTS_SUPPLIER','PROFESSIONAL_SERVICES','RENT','TIRE_SUPPLIER','UTILITIES'), primary key (id)) engine=InnoDB;
create table work_orders (appointment_id bigint, assigned_employee_id bigint, completed_at datetime(6), created_at datetime(6), customer_id bigint, id bigint not null auto_increment, invoice_id bigint, location_id bigint, shop_id bigint, started_at datetime(6), updated_at datetime(6), vehicle_ready_at datetime(6), customer_name varchar(255) not null, email varchar(255), notes TEXT, phone varchar(255), vehicle varchar(255), service_type enum ('BALANCING','INSTALLATION','REPAIR','ROTATION') not null, status enum ('CANCELLED','COMPLETED','IN_PROGRESS','PENDING','VEHICLE_READY') not null, primary key (id)) engine=InnoDB;
create table work_shifts (break_minutes integer not null, shift_date date not null, worked_hours decimal(6,2), clock_in datetime(6) not null, clock_out datetime(6), created_at datetime(6), employee_id bigint not null, id bigint not null auto_increment, updated_at datetime(6), notes TEXT, primary key (id)) engine=InnoDB;
